import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { CasinoJackpotUpdateParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/CasinoJackpotUpdateParser';

export class CasinoJackpotUpdateEvent extends MessageEvent implements IMessageEvent
{
constructor(callback: Function)
{
super(callback, CasinoJackpotUpdateParser);

// 🔍 CONFIRM EVENT WAS CREATED (packet reached client)
console.log('[🎰] CasinoJackpotUpdateEvent → constructor fired');
}

public getParser(): CasinoJackpotUpdateParser
{
const parser = this.parser as CasinoJackpotUpdateParser;

// 🔍 CONFIRM PARSER IS ATTACHED AND DATA IS READY
console.log(
'[🎰] CasinoJackpotUpdateEvent → getParser()',
{
amount: parser?.amount,
raw: parser?.amountRaw
}
);

return parser;
}
}
